import React from 'react'
import {Button} from '@material-ui/core'
import {withStyles} from '@material-ui/core/styles'
import { useNavigate } from "react-router-dom"

const StyledButton = withStyles({
    root: {
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        height: "44px",
        padding: "0 25px",
        boxSizing: "border-box",
        borderRadius: 0, 
        background: "#3071f2",
        color: "#fff",
        transform: "none",
        transition: "background .3s,border-color .3s,color .3s",
        "&:hover": {
            background:  "#2a06ba"
          },
    },
    label: {
      textTransform: 'capitalize',
    },
  })(Button);

function CustomBtn(props: any) {
  const nav = useNavigate()
  
  if (props.data && !props.data.restaurant_id) {
    return (
      <StyledButton onClick={() => props.data.current.scrollIntoView({ behavior: 'smooth', block: 'start' })} variant="contained">{props.txt}</StyledButton>
      )
    } else {
    const googleurl = `https://google.com/search?q=${props.data.name.split(' ').join('+')}`
    return <StyledButton onClick={() => {
      props.data.booking_url ? nav(props.data.booking_url) : window.location.href=googleurl
    }} variant="contained">{props.txt}</StyledButton>
  }

  return <></>
}

export default CustomBtn